fn containsFd(fds: []const posix.fd_t, fd: posix.fd_t) bool {
    for (fds) |item| {
        if (item == fd) return true;
    }
    return false;
}

fn removeFd(fds: *std.ArrayListAligned(posix.fd_t, null), fd: posix.fd_t) void {
    for (fds.items, 0..) |item, idx| {
        if (item == fd) {
            _ = fds.swapRemove(idx);
            return;
        }
    }
}

