   503	    fn nextStatusRefreshDelayMs(self: *const Server, now: i64) ?c_int {
   504	        var next_refresh_at: ?i64 = null;
   505	
   506	        for (self.clients.items) |client| {
   507	            const session = client.session orelse continue;
   508	            if (self.sessionStartupRelayActive(session)) continue;
   509	            if (!session.options.status or session.options.status_interval == 0) continue;
   510	
   511	            if (session.status_next_refresh_at == 0 or session.status_next_refresh_at <= now) {
   512	                return 0;
   513	            }
   514	
   515	            next_refresh_at = if (next_refresh_at) |current|
   516	                @min(current, session.status_next_refresh_at)
   517	            else
   518	                session.status_next_refresh_at;
   519	        }
   520	
   521	        const refresh_at = next_refresh_at orelse return null;
   522	        const delay_s = @max(refresh_at - now, 0);
   523	        const delay_ms: i64 = delay_s * std.time.ms_per_s;
   524	        return @intCast(@min(delay_ms, idle_poll_timeout_ms));
   525	    }
   526	
   527	    fn nextPollTimeoutMs(self: *const Server) c_int {
   528	        if (self.hasPendingClientOutput() or self.hasPendingPaneWrites()) {
   529	            return pending_write_retry_timeout_ms;
   530	        }
   531	
   532	        var now: i64 = 0;
   533	        _ = time(&now);
   534	        return self.nextStatusRefreshDelayMs(now) orelse idle_poll_timeout_ms;
   535	    }
