   597	    /// Load a configuration file by executing it as commands.
   598	    /// Returns true once a file was successfully opened, even if it was empty.
   599	    pub fn loadConfigFile(self: *Server, path: []const u8) bool {
   600	        const expanded_path = config_path.expandHomePath(self.allocator, path) catch return false;
   601	        defer self.allocator.free(expanded_path);
   602	
   603	        var path_buf: [4096]u8 = .{0} ** 4096;
   604	        if (expanded_path.len >= path_buf.len) return false;
   605	        @memcpy(path_buf[0..expanded_path.len], expanded_path);
   606	        const cpath: [*:0]const u8 = @ptrCast(path_buf[0..expanded_path.len :0]);
   607	        const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
   608	        if (fd < 0) return false;
   609	        defer _ = std.c.close(fd);
   610	
   611	        var content_buf: [65536]u8 = undefined;
   612	        var total: usize = 0;
   613	        while (total < content_buf.len) {
   614	            const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
   615	            if (n <= 0) break;
   616	            total += @intCast(n);
   617	        }
   618	        if (total == 0) return true;
   619	
   620	        var registry = cmd.Registry.init(self.allocator);
   621	        defer registry.deinit();
   622	        registry.registerBuiltins() catch return true;
   623	
   624	        var ctx = cmd.Context{
   625	            .server = self,
   626	            .session = self.default_session,
   627	            .window = if (self.default_session) |s| s.active_window else null,
   628	            .pane = if (self.default_session) |s| if (s.active_window) |w| w.active_pane else null else null,
   629	            .allocator = self.allocator,
   630	            .registry = &registry,
   631	            .binding_manager = &self.binding_manager,
   632	        };
   633	
   634	        var parser = config_parser.ConfigParser.init(self.allocator, content_buf[0..total]);
   635	        var commands = parser.parseAll() catch return true;
   636	        defer {
   637	            for (commands.items) |*command| command.deinit(self.allocator);
   638	            commands.deinit(self.allocator);
   639	        }
   640	
   641	        for (commands.items) |*command| {
   642	            registry.executeParsed(&ctx, command) catch {};
   643	        }
   644	        return true;
   645	    }
