   690	    pub fn createSession(self: *Server, name: []const u8, shell: [:0]const u8, cols: u32, rows: u32) !*Session {
   691	        const session = try Session.init(self.allocator, name);
   692	        errdefer session.deinit();
   693	        try self.applySessionStatusDefaults(session);
   694	
   695	        const window = try Window.init(self.allocator, name, cols, rows);
   696	        errdefer window.deinit();
   697	        try self.applyWindowDefaults(window);
   698	
   699	        const pane = try Pane.init(self.allocator, cols, rows);
   700	        errdefer pane.deinit();
   701	
   702	        var pty = try Pty.openPty();
   703	        try pty.forkExec(shell, null);
   704	        pty.resize(@intCast(cols), @intCast(rows));
   705	        pane.fd = pty.master_fd;
   706	        pane.pid = pty.pid;
   707	
   708	        try window.addPane(pane);
   709	        try session.addWindow(window);
   710	        try self.sessions.append(self.allocator, session);
   711	        if (self.default_session == null) self.default_session = session;
   712	        // Use trackPane to register the pane for I/O processing and perform an
   713	        // immediate drain on any startup output already waiting on the PTY.
   714	        try self.trackPane(pane, cols, rows);
   715	
   716	        self.fireHooks(.after_new_session);
   717	
   718	        return session;
   719	    }
